checker_dsl:
EXISTS (`method call MC`) {
  AND {
    (`MC is a call to a method M`),
    (`M has the exact name "addCookie" and is declared in a type T, where T is a class or interface with qualified name "javax.servlet.http.HttpServletResponse" or "jakarta.servlet.http.HttpServletResponse"`),
    NOT {
      EXISTS (`expression E`) {
        AND {
          (`E is the argument at index 0 of method call MC`),
          (`E flows to a secure cookie expression`)
        }
      }
    }
  }
}
